use colors;
use drawable;
use gui;

drawable.Rectangle player;

void function redraw(gui.Canvas canvas) {
    canvas.fill(colors.RGB(20, 24, 32));
    canvas.draw(player);
}

void function init(gui.Canvas canvas) {
    player.x = 160;
    player.y = 85;
    player.width = 90;
    player.height = 60;
    player.fill_color = colors.RGB(34, 145, 188);
    player.border_width = 5;
    player.border_color = colors.TRANSPARENT;
    redraw(canvas);
}

void function key_pressed(gui.Canvas canvas, gui.KeyboardEvent event) {
    if (event.key == "R") {
        player.border_color = colors.RED;
    }
    if (event.key == "G") {
        player.border_color = colors.GREEN;
    }
    if (event.key == "B") {
        player.border_color = colors.BLUE;
    }
    redraw(canvas);
}

main() {
    gui.Window win;
    win.width = 450;
    win.height = 290;
    win.title = "Клавиатура";

    gui.Canvas canvas;
    canvas.x = 20;
    canvas.y = 20;
    canvas.width = 400;
    canvas.height = 220;
    canvas.on_init = init;
    canvas.on_key_pressed = key_pressed;

    win.add_child(canvas);
    win.show();
}

